mapper.select:
select ipom.*,su.real_name create_user_name
from im_push_object_manage ipom
left join sys_user su on ipom.create_user_id = su.user_id
where 1=1

        and ipom.object_area_id = #{imPushObjectManage.objectAreaId}



        and ipom.push_object_type = #{imPushObjectManage.pushObjectType}



        and ipom.push_object_id = #{imPushObjectManage.pushObjectId}



        and ipom.push_object_name like concat('%',#{imPushObjectManage.pushObjectName},'%')



        and ipom.class_type = #{imPushObjectManage.classType}



        and ipom.bind_state = #{imPushObjectManage.bindState}



  order by ipom.create_time desc
